import base64
import pickle
import json
from datetime import datetime
from typing import Any, Dict, List
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


def process_batch_job(job_data: Dict[str, Any]) -> Dict[str, Any]:
    """
    Process a single batch job with the deserialized data.
    
    Args:
        job_data: Dictionary containing job information and data
        
    Returns:
        Dictionary with processing results
    """
    job_id = job_data.get('job_id', 'unknown')
    job_type = job_data.get('job_type', 'default')
    data = job_data.get('data', {})
    
    logger.info(f"Processing job {job_id} of type {job_type}")
    
    result = {
        'job_id': job_id,
        'job_type': job_type,
        'status': 'success',
        'processed_at': datetime.utcnow().isoformat(),
        'records_processed': 0,
        'errors': []
    }
    
    try:
        if job_type == 'data_transformation':
            records = data.get('records', [])
            transformed_records = []
            for record in records:
                transformed_record = {k: str(v).upper() if isinstance(v, str) else v 
                                     for k, v in record.items()}
                transformed_records.append(transformed_record)
            result['records_processed'] = len(transformed_records)
            result['output'] = transformed_records
            
        elif job_type == 'aggregation':
            values = data.get('values', [])
            result['records_processed'] = len(values)
            result['output'] = {
                'sum': sum(values),
                'avg': sum(values) / len(values) if values else 0,
                'min': min(values) if values else None,
                'max': max(values) if values else None,
                'count': len(values)
            }
            
        elif job_type == 'model_prediction':
            features = data.get('features', [])
            model_params = data.get('model_params', {})
            predictions = []
            for feature_set in features:
                prediction = sum(feature_set) * model_params.get('weight', 1.0)
                predictions.append(prediction)
            result['records_processed'] = len(predictions)
            result['output'] = predictions
            
        elif job_type == 'data_validation':
            records = data.get('records', [])
            schema = data.get('schema', {})
            valid_records = []
            invalid_records = []
            
            for idx, record in enumerate(records):
                is_valid = True
                for field, field_type in schema.items():
                    if field not in record:
                        is_valid = False
                        result['errors'].append(f"Record {idx}: Missing field {field}")
                    elif not isinstance(record[field], eval(field_type)):
                        is_valid = False
                        result['errors'].append(f"Record {idx}: Invalid type for {field}")
                
                if is_valid:
                    valid_records.append(record)
                else:
                    invalid_records.append(record)
            
            result['records_processed'] = len(records)
            result['output'] = {
                'valid_count': len(valid_records),
                'invalid_count': len(invalid_records),
                'valid_records': valid_records,
                'invalid_records': invalid_records
            }
            
        elif job_type == 'batch_computation':
            operations = data.get('operations', [])
            results_list = []
            for operation in operations:
                op_type = operation.get('type')
                operands = operation.get('operands', [])
                
                if op_type == 'multiply':
                    result_val = 1
                    for operand in operands:
                        result_val *= operand
                elif op_type == 'add':
                    result_val = sum(operands)
                elif op_type == 'subtract':
                    result_val = operands[0] - sum(operands[1:]) if len(operands) > 1 else 0
                else:
                    result_val = None
                    
                results_list.append(result_val)
            
            result['records_processed'] = len(operations)
            result['output'] = results_list
            
        else:
            result['status'] = 'warning'
            result['message'] = f"Unknown job type: {job_type}. Job data stored but not processed."
            result['output'] = data
            
    except Exception as e:
        logger.error(f"Error processing job {job_id}: {str(e)}")
        result['status'] = 'error'
        result['error_message'] = str(e)
        result['errors'].append(str(e))
    
    return result


def pubsub_handler(event, context):
    """
    Cloud Function triggered by Pub/Sub.
    Processes messages containing pickled Python objects.
    
    Args:
        event: The dictionary with data specific to this type of event.
        context: Metadata of triggering event.
    """
    try:
        if 'data' not in event:
            logger.error("No data field in Pub/Sub message")
            return
        
        message_data = base64.b64decode(event['data'])
        
        deserialized_data = pickle.loads(message_data)
        
        logger.info(f"Deserialized message data type: {type(deserialized_data)}")
        
        if isinstance(deserialized_data, dict):
            job_data = deserialized_data
        elif isinstance(deserialized_data, list):
            job_data = {
                'job_id': context.event_id if context else 'unknown',
                'job_type': 'batch_list',
                'data': {'items': deserialized_data}
            }
        else:
            job_data = {
                'job_id': context.event_id if context else 'unknown',
                'job_type': 'generic',
                'data': {'payload': deserialized_data}
            }
        
        result = process_batch_job(job_data)
        
        logger.info(f"Job processing completed: {result['status']}")
        logger.info(f"Records processed: {result['records_processed']}")
        
        if result['status'] == 'error':
            logger.error(f"Job failed with error: {result.get('error_message')}")
        
        if result.get('errors'):
            logger.warning(f"Job completed with {len(result['errors'])} errors")
        
        return result
        
    except pickle.UnpicklingError as e:
        logger.error(f"Failed to unpickle message data: {str(e)}")
        raise
    except Exception as e:
        logger.error(f"Unexpected error processing Pub/Sub message: {str(e)}")
        raise


def process_pubsub_message(event, context):
    """
    Main entry point for Cloud Function.
    """
    return pubsub_handler(event, context)